import React from "react";

function Gallery() {
  return (
    <div className="section">
      <h2>Gallery</h2>
      <div className="gallery">
        <img src="https://source.unsplash.com/300x200/?resort" />
        <img src="https://source.unsplash.com/300x200/?hotel" />
        <img src="https://source.unsplash.com/300x200/?beach" />
      </div>
    </div>
  );
}

export default Gallery;
